SELECT

FROM t_group_apply a



	${dataScope}

		AND a.uid = #{u.id}


		AND a.uid2 = #{uid2.id}


		AND a.group_id = #{group.id}


		AND a.state = #{state}


		AND a.type = #{type}


		AND a.showids LIKE concat('%',#{showids},'%')


		AND (`group`.name LIKE concat('%',#{key},'%') or `group`.idno = #{key})




		ORDER BY ${page.orderBy}


		ORDER BY a.create_date DESC

